for (let i = 0; i < nums.length; i++) {
  const complement = target - nums[i];
  if (complement in seen) {
    result = [seen[complement], i];
    break;
  }
  seen[nums[i]] = i;
}
// result is [0, 1]`,conceptContext:"Instead of searching for matching pairs using nested loops, caching checked numbers in a lookup dictionary resolves target matches in constant O(1) time per element.",description:"Let's build on basic dictionary lookups to solve a classic DSA algorithm in linear time!\n\nWrite a function `twoSumLookup(nums, target)` that seeks the index positions of two numbers in `nums` that add up to `target`.\n\nYou must achieve **O(N) linear runtime** by using an object as a coordinate lookup tracker. Nested loops are forbidden!",codeTemplate:`function twoSumLookup(nums, target) {
